def scheme_eval(expr, env):
    if isinstance(expr, int):
        return expr
    if isinstance(expr, str):
        return env[expr]

    operator = scheme_eval(expr[0], env)
    arguments = []
    for operand in expr[1:]:
        arguments.append(scheme_eval(operand, env))
    return scheme_apply(operator, arguments)


def scheme_apply(procedure, arguments):
    return procedure(*arguments)


env = {
    "+": lambda x, y: x + y,
    "*": lambda x, y: x * y,
}

program = ["+", 2, ["*", 3, 4]]
result = scheme_eval(program, env)
